    print("Output: The number is negative.")
else:
    print("Output: The number is zero.")

num = int(input("Enter a number: "))
if num % 2 == 0:
    print("Output: The number is even.")
else:
    print("Output: The number is odd.")

num = int(input("Enter a number: "))
for i in range(1, 11):
    print(f"{num} x {i} = {num * i}")

n = int(input("Enter N: "))
for i in range(1, n+1):
    print(i, end=", " if i < n else "\n")

a = float(input("Enter first number: "))
b = float(input("Enter second number: "))
if a > b:
    print("Output:", a, "is larger.")
else:
    print("Output:", b, "is larger.")
